import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"44. Rosters","description":"","frontmatter":{"title":"44. Rosters","eba":"Biomedical Engineers 2025-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/44-rosters.md","filePath":"ebas/biomedical-engineers/hours-of-work/44-rosters.md"}'),a={name:"ebas/biomedical-engineers/hours-of-work/44-rosters.md"};function n(i,e,l,p,c,g){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_44-rosters" tabindex="-1">44. Rosters <a class="header-anchor" href="#_44-rosters" aria-label="Permalink to &quot;44. Rosters&quot;">​</a></h1><p><strong>44.1</strong> Posting a Roster</p><p><strong>(a)</strong> Where Employees work according to a roster, a roster of at least fourteen day’s duration setting out an Employee’s:</p><p><strong>(i)</strong> normal working hours,</p><p><strong>(ii)</strong> start and finish times, and</p><p><strong>(iii)</strong> meal intervals (unless self-managed), will be posted in a place or places to allow an Employee to have ready access to the roster while at work, which may include ready electronic access.</p><p><strong>(b)</strong> The roster must be posted at least two weeks before the commencement of the roster period.</p><p><strong>44.2</strong> Altering a Roster Except in the case of:</p><p><strong>(a)</strong> personal/carer’s leave (<a href="/eba/ebas/biomedical-engineers/leave/54-personal-carer-s-leave.html">clause 54</a>),</p><p><strong>(b)</strong> compassionate leave (<a href="/eba/ebas/biomedical-engineers/leave/57-compassionate-leave.html">clause 57</a>),</p><p><strong>(c)</strong> family violence leave (<a href="/eba/ebas/biomedical-engineers/leave/56-family-violence-leave.html">clause 56</a>),</p><p><strong>(d)</strong> an Employee resigning without notice, or</p><p><strong>(e)</strong> any other emergency, the roster shall not be altered without at least seven days’ notice being given to the Employee affected by such alteration.</p><p><strong>44.1</strong> On-call</p><p><strong>(a)</strong> An Employee may be rostered to be &quot;on call&quot; (that is to be available to be recalled to duty in that period of time beyond the Employee&#39;s rostered hours of duty).</p><p><strong>(b)</strong> Where reasonably practicable, an Employee will be provided at least 28 days’ notice of the requirement to be on call.</p><p>Plain language terms: rostering, shift roster, duty roster.</p>',17)])])}const h=t(a,[["render",n]]);export{m as __pageData,h as default};
